#!/usr/bin/env node
// One-time migration: carve the pure, DOM-free pipeline out of the monolithic
// paper-rig-workbench.html into standalone ESM packages, VERBATIM, so numeric
// output is byte-identical to the original (gated by fixtures/).
//
// After this runs once, the generated package files ARE the source of truth and
// are edited directly; paper-rig-workbench.html becomes a build artifact
// (regenerated by `rig build-workbench`). This script is retained only to
// document the provenance of the extraction.
//
//   node scripts/extract-packages.mjs
//
// It re-derives top-level declaration spans with a small regex-aware scanner
// (handles strings, templates, regex literals, comments) and groups them into
// schema / compiler buckets. The only edits to the verbatim text are three
// `rigs[state.model]` -> `state.rig` rewrites (the pipeline's sole reads of the
// workbench's global rig table); every `state.*` read is satisfied by an
// injected module-scoped render context.

import { readFileSync, writeFileSync } from 'node:fs';
import { fileURLToPath } from 'node:url';
import { dirname, join } from 'node:path';

const ROOT = join(dirname(fileURLToPath(import.meta.url)), '..');
const HTML = readFileSync(join(ROOT, 'paper-rig-workbench.html'), 'utf8');

// ---- isolate the main application script -------------------------------------
const scriptStart = HTML.indexOf('<script>', HTML.indexOf('id="workbench-maintainer-spec"')) + '<script>'.length;
const body = HTML.slice(scriptStart, HTML.indexOf('</script>', scriptStart));
const N = body.length;

// ---- regex-aware top-level scanner -------------------------------------------
const REGEX_PREV = new Set('(,=:[!&|?{;}+-*/%<>~^'.split(''));
function lastSig(i) { let j = i - 1; while (j >= 0 && /\s/.test(body[j])) j--; return j; }
function isRegexAt(i) {
  const j = lastSig(i); if (j < 0) return true;
  if (REGEX_PREV.has(body[j])) return true;
  let k = j; while (k >= 0 && /[A-Za-z]/.test(body[k])) k--;
  const w = body.slice(k + 1, j + 1);
  return ['return', 'typeof', 'instanceof', 'in', 'of', 'new', 'delete', 'void', 'do', 'else', 'case'].includes(w);
}
function skip(i) {
  const c = body[i];
  if (c === "'" || c === '"') { let j = i + 1; for (; j < N; j++) { if (body[j] === '\\') { j++; continue; } if (body[j] === c) return j + 1; } return j; }
  if (c === '`') { let j = i + 1; for (; j < N; j++) { if (body[j] === '\\') { j++; continue; } if (body[j] === '`') return j + 1; if (body[j] === '$' && body[j + 1] === '{') { j = matchBrace(j + 1) - 1; } } return j; }
  if (c === '/' && body[i + 1] === '/') { let j = i + 2; while (j < N && body[j] !== '\n') j++; return j; }
  if (c === '/' && body[i + 1] === '*') { let j = i + 2; while (j < N && !(body[j] === '*' && body[j + 1] === '/')) j++; return j + 2; }
  if (c === '/' && isRegexAt(i)) { let j = i + 1, cls = false; for (; j < N; j++) { const d = body[j]; if (d === '\\') { j++; continue; } if (d === '[') cls = true; else if (d === ']') cls = false; else if (d === '/' && !cls) { j++; break; } else if (d === '\n') break; } while (j < N && /[a-z]/.test(body[j])) j++; return j; }
  return i + 1;
}
function isSkippable(i) { const c = body[i]; return c === "'" || c === '"' || c === '`' || (c === '/' && (body[i + 1] === '/' || body[i + 1] === '*' || isRegexAt(i))); }
function matchBrace(i) { let d = 0, j = i; while (j < N) { if (isSkippable(j)) { j = skip(j); continue; } if (body[j] === '{') d++; else if (body[j] === '}') { d--; if (d === 0) return j + 1; } j++; } return j; }
function matchParen(i) { let d = 0, j = i; while (j < N) { if (isSkippable(j)) { j = skip(j); continue; } if (body[j] === '(') d++; else if (body[j] === ')') { d--; if (d === 0) return j + 1; } j++; } return j; }

const units = [];
let i = 0;
while (i < N) {
  while (i < N && /\s/.test(body[i])) i++;
  if (i >= N) break;
  if (/^function[\s(]/.test(body.slice(i, i + 9))) {
    const nameM = /^function\s+([A-Za-z0-9_$]+)/.exec(body.slice(i, i + 120));
    const po = body.indexOf('(', i), pc = matchParen(po), bo = body.indexOf('{', pc), end = matchBrace(bo);
    units.push({ kind: 'function', name: nameM ? nameM[1] : '?', start: i, end });
    i = end; continue;
  }
  if (/^(const|let|var)[\s]/.test(body.slice(i, i + 6))) {
    let j = i, d = 0;
    while (j < N) { if (isSkippable(j)) { j = skip(j); continue; } const c = body[j]; if ('{(['.includes(c)) d++; else if ('})]'.includes(c)) d--; else if (c === ';' && d === 0) { j++; break; } j++; }
    units.push({ kind: 'decl', start: i, end: j });
    i = j; continue;
  }
  let j = i, d = 0;
  while (j < N) { if (isSkippable(j)) { j = skip(j); continue; } const c = body[j]; if ('{(['.includes(c)) d++; else if ('})]'.includes(c)) d--; else if (c === ';' && d === 0) { j++; break; } j++; }
  units.push({ kind: 'stmt', start: i, end: j });
  i = j;
}

const text = (idx) => body.slice(units[idx].start, units[idx].end);

// ---- bucket assignments (by unit index in the scanned script) ----------------
// schema: V/C, plate & joint factories, axisVector, cloneData, groupBy polyfill
const SCHEMA_EXPORTED = [0, 1, 2, 3, 4, 5, 6, 219, 154];
const SCHEMA_SIDE_EFFECT = [155]; // Object.groupBy polyfill

// compiler: the pure pipeline + validation, in SOURCE ORDER so the monkey-patch
// capture/reassign sequence (baseCompileRig -> wrap -> wrap; raw -> cache -> wrap)
// replays exactly as in the original.
const COMPILER = [
  169, 170, 171, 172, 173, 174, 175, 176, 177, 178, 179, 181, 182, 183, 184, 185,
  186, 187, 188, 189, 190, 191, 192, 193, 194, 195, 196, 197, 198, 199, 200, 201,
  202, 203, 220, 221, 222, 223, 224, 225, 226, 227, 228, 229, 230, 231, 232, 233,
  237, 238, 239, 240, 241, 242, 243, 244, 251,
];

// The pipeline's only reads of the global rig table -> the injected context rig.
const RIGS_EDIT = { 179: true, 232: true, 251: true };
function compilerUnitText(idx) {
  let t = text(idx);
  if (RIGS_EDIT[idx]) t = t.replaceAll('rigs[state.model]', 'state.rig');
  return t;
}

// Public API names exported from the compiler core.
const COMPILER_EXPORTS = [
  'euler', 'solveWorld', 'worldJoints', 'cameraBasisAt', 'cameraBasis', 'projectWithBasis',
  'projected', 'contactIds', 'boneForPlate', 'bodyRegionFor', 'bindPositions',
  'absoluteSideForJoint', 'sideForPlate', 'paletteRoleFor', 'lodTierFor', 'mergeGroupFor',
  'defaultCompositingGroup', 'generatedGaskets', 'convexHull', 'coreOccluderPoints',
  'coreOccluderMarkup', 'gasketMarkup', 'mirrorPlate', 'appendageIsFar', 'gasketIsFar',
  'shapeMarkup', 'svgMarkup', 'groundContactSet', 'compiledBounds', 'plateGeometry',
  'compiledPlate', 'compiledGasket', 'compiledJoints', 'standardAnchors', 'paintRegions',
  'compiledClips', 'reusablePaintLibrary', 'packageValidation', 'compileRig', 'rigPayload',
  'directionalValidation', 'preservedClipLengthsPass', 'bilateralHeadingSwapPass', 'exportedSvg',
];

// ---- emit packages/schema/index.js -------------------------------------------
const schemaOut = [
  '// @paper-rig/schema — paper-rig/1 constants, vector/plate/joint primitives.',
  '// Extracted verbatim from paper-rig-workbench.html (see scripts/extract-packages.mjs).',
  '',
  ...SCHEMA_EXPORTED.map((idx) => 'export ' + text(idx)),
  '',
  '// Object.groupBy polyfill for runtimes below Node 20.10 (used by the compiler).',
  ...SCHEMA_SIDE_EFFECT.map((idx) => text(idx)),
  '',
].join('\n');
writeFileSync(join(ROOT, 'packages/schema/index.js'), schemaOut);

// ---- emit packages/compiler/core.js ------------------------------------------
const compilerOut = [
  '// @paper-rig/compiler core — the pure paper-rig/1 pipeline (posing, projection,',
  '// SVG generation, package compilation, structural + directional validation).',
  '// Extracted VERBATIM from paper-rig-workbench.html (see scripts/extract-packages.mjs);',
  '// every `state.*` read is served by the injected render context below instead of',
  '// the workbench UI, so this module is fully DOM-free and runnable under Node.',
  '',
  "import { V, C, joint, plate, spanPlate, taperedSpanPlate, polygonPlate, pathPlate, axisVector, cloneData } from '@paper-rig/schema';",
  '',
  '// Injected render context. The workbench passes its live UI state through the',
  '// public API (index.js); the CLI passes flags + rig defaults. Identity values',
  '// here reproduce the original fresh-load output exactly.',
  'export const state = {',
  '  rig: null, model: "", clip: "idle", t: 0, elev: 90, az: 0,',
  '  height: 1, width: 1, bones: false, contacts: false,',
  '  modelTransforms: {}, jointTransforms: {},',
  '};',
  '',
  ...COMPILER.map((idx) => compilerUnitText(idx)),
  '',
  `export { ${COMPILER_EXPORTS.join(', ')} };`,
  '',
].join('\n');
writeFileSync(join(ROOT, 'packages/compiler/core.js'), compilerOut);

console.log(`schema: ${SCHEMA_EXPORTED.length} exported units + polyfill`);
console.log(`compiler: ${COMPILER.length} units, ${COMPILER_EXPORTS.length} exports`);
console.log('Wrote packages/schema/index.js and packages/compiler/core.js');
